package com.example.samlsp;

import jakarta.servlet.Filter;
import jakarta.servlet.FilterChain;
import jakarta.servlet.ServletException;
import jakarta.servlet.ServletRequest;
import jakarta.servlet.ServletResponse;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;

import java.io.IOException;

public class SecurityHeadersFilter implements Filter {
    @Override
    public void doFilter(ServletRequest request, ServletResponse response, FilterChain chain) throws IOException, ServletException {
        HttpServletResponse resp = (HttpServletResponse) response;
        resp.setHeader("X-Content-Type-Options", "nosniff");
        resp.setHeader("X-Frame-Options", "DENY");
        resp.setHeader("Referrer-Policy", "no-referrer");
        resp.setHeader("X-XSS-Protection", "0");
        chain.doFilter(request, response);
    }
}

package com.example.samlsp.web;

import com.example.samlsp.saml.SamlAuthenticationService;
import com.example.samlsp.saml.SamlPrincipal;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpSession;
import org.springframework.http.HttpStatus;
import org.springframework.http.MediaType;
import org.springframework.http.ResponseEntity;
import org.springframework.util.MultiValueMap;
import org.springframework.web.bind.annotation.*;

import java.net.URI;
import java.util.Map;

@RestController
@RequestMapping("/saml")
public class SamlAcsController {

    public static final String SESSION_PRINCIPAL_KEY = "SAML_PRINCIPAL";
    public static final String SESSION_ATTRIBUTES_KEY = "SAML_ATTRIBUTES";

    private final SamlAuthenticationService samlAuthenticationService;

    public SamlAcsController(SamlAuthenticationService samlAuthenticationService) {
        this.samlAuthenticationService = samlAuthenticationService;
    }

    @PostMapping(value = "/acs", consumes = MediaType.APPLICATION_FORM_URLENCODED_VALUE)
    public ResponseEntity<?> acs(@RequestBody MultiValueMap<String, String> form, HttpServletRequest request) {
        String samlResponse = form.getFirst("SAMLResponse");
        String relayState = form.getFirst("RelayState");

        if (samlResponse == null || samlResponse.isBlank()) {
            return ResponseEntity.status(HttpStatus.BAD_REQUEST).body("Missing SAMLResponse");
        }

        SamlPrincipal principal = samlAuthenticationService.processSamlResponse(samlResponse);

        HttpSession session = request.getSession(true);
        session.setAttribute(SESSION_PRINCIPAL_KEY, principal);
        session.setAttribute(SESSION_ATTRIBUTES_KEY, principal.attributes());

        String target = (relayState != null && !relayState.isBlank()) ? relayState : "/";

        return ResponseEntity.status(HttpStatus.FOUND).location(URI.create(target)).build();
    }

    @GetMapping("/me")
    public ResponseEntity<?> me(HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        if (session == null) return ResponseEntity.status(HttpStatus.UNAUTHORIZED).build();

        SamlPrincipal principal = (SamlPrincipal) session.getAttribute(SESSION_PRINCIPAL_KEY);
        Map<String, Object> attrs = (Map<String, Object>) session.getAttribute(SESSION_ATTRIBUTES_KEY);

        if (principal == null) return ResponseEntity.status(HttpStatus.UNAUTHORIZED).build();

        return ResponseEntity.ok(Map.of(
                "nameId", principal.nameId(),
                "sessionIndex", principal.sessionIndex(),
                "issuer", principal.issuer(),
                "attributes", attrs
        ));
    }

    @PostMapping("/logout")
    public ResponseEntity<?> logout(HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        if (session != null) session.invalidate();
        return ResponseEntity.noContent().build();
    }
}

