package com.example.samlsp.saml;

import org.springframework.stereotype.Component;
import org.w3c.dom.*;

import javax.xml.XMLConstants;
import javax.xml.namespace.NamespaceContext;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.xpath.*;
import java.io.ByteArrayInputStream;
import java.nio.charset.StandardCharsets;
import java.time.Instant;
import java.util.*;
import java.util.Base64;

@Component
public class SamlResponseParser {

    private static final String NS_SAMLP = "urn:oasis:names:tc:SAML:2.0:protocol";
    private static final String NS_SAML = "urn:oasis:names:tc:SAML:2.0:assertion";
    private static final String NS_DS = "http://www.w3.org/2000/09/xmldsig#";

    public SamlPrincipal parseBase64Response(String base64Response) {
        byte[] decoded = Base64.getDecoder().decode(base64Response);
        String xml = new String(decoded, StandardCharsets.UTF_8);
        return parseXml(xml);
    }

    public SamlPrincipal parseXml(String xml) {
        Document doc = parseSecure(xml);

        XPath xpath = newXPath();

        String issuer = evalString(xpath, doc, "/samlp:Response/saml:Issuer");
        String nameId = evalString(xpath, doc, "/samlp:Response/saml:Assertion/saml:Subject/saml:NameID");
        if (nameId == null || nameId.isBlank()) {
            nameId = evalString(xpath, doc, "/samlp:Response/saml:Assertion/saml:Subject/saml:EncryptedID");
        }

        String sessionIndex = evalString(xpath, doc, "/samlp:Response/saml:Assertion/saml:AuthnStatement/@SessionIndex");

        String notBeforeStr = evalString(xpath, doc, "/samlp:Response/saml:Assertion/saml:Conditions/@NotBefore");
        String notOnOrAfterStr = evalString(xpath, doc, "/samlp:Response/saml:Assertion/saml:Conditions/@NotOnOrAfter");

        Instant notBefore = parseInstantLenient(notBeforeStr);
        Instant notOnOrAfter = parseInstantLenient(notOnOrAfterStr);

        Map<String, Object> attributes = extractAttributes(xpath, doc);

        return new SamlPrincipal(nameId, sessionIndex, issuer, notBefore, notOnOrAfter, attributes);
    }

    private Map<String, Object> extractAttributes(XPath xpath, Document doc) {
        Map<String, Object> attrs = new LinkedHashMap<>();

        NodeList attrNodes = evalNodeList(xpath, doc,
                "/samlp:Response/saml:Assertion/saml:AttributeStatement/saml:Attribute");

        for (int i = 0; i < attrNodes.getLength(); i++) {
            Element attr = (Element) attrNodes.item(i);
            String name = attr.getAttribute("Name");
            if (name == null || name.isBlank()) name = attr.getAttribute("FriendlyName");
            if (name == null || name.isBlank()) continue;

            NodeList values = attr.getElementsByTagNameNS(NS_SAML, "AttributeValue");
            if (values == null || values.getLength() == 0) {
                attrs.put(name, null);
                continue;
            }

            List<String> list = new ArrayList<>();
            for (int j = 0; j < values.getLength(); j++) {
                Node v = values.item(j);
                String text = normalizeValueNode(v);
                if (text != null) list.add(text);
            }

            if (list.isEmpty()) {
                attrs.put(name, null);
            } else if (list.size() == 1) {
                attrs.put(name, list.get(0));
            } else {
                attrs.put(name, List.copyOf(list));
            }
        }

        NodeList groupValues = evalNodeList(xpath, doc,
                "/samlp:Response/saml:Assertion/saml:AttributeStatement/saml:Attribute[@Name='groups' or @FriendlyName='groups']/saml:AttributeValue");
        if (groupValues != null && groupValues.getLength() > 0 && !attrs.containsKey("groups")) {
            List<String> groups = new ArrayList<>();
            for (int i = 0; i < groupValues.getLength(); i++) {
                String g = normalizeValueNode(groupValues.item(i));
                if (g != null) groups.add(g);
            }
            if (!groups.isEmpty()) attrs.put("groups", groups.size() == 1 ? groups.get(0) : List.copyOf(groups));
        }

        return attrs;
    }

    private String normalizeValueNode(Node node) {
        if (node == null) return null;
        String text = node.getTextContent();
        if (text == null) return null;
        text = text.trim();
        return text.isEmpty() ? null : text;
    }

    private Document parseSecure(String xml) {
        try {
            DocumentBuilderFactory dbf = DocumentBuilderFactory.newInstance();
            dbf.setNamespaceAware(true);
            dbf.setExpandEntityReferences(false);
            dbf.setXIncludeAware(false);

            trySet(dbf, XMLConstants.FEATURE_SECURE_PROCESSING, true);
            trySet(dbf, "http://apache.org/xml/features/disallow-doctype-decl", true);
            trySet(dbf, "http://xml.org/sax/features/external-general-entities", false);
            trySet(dbf, "http://xml.org/sax/features/external-parameter-entities", false);
            trySet(dbf, "http://apache.org/xml/features/nonvalidating/load-external-dtd", false);

            dbf.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
            dbf.setAttribute(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");

            DocumentBuilder db = dbf.newDocumentBuilder();
            return db.parse(new ByteArrayInputStream(xml.getBytes(StandardCharsets.UTF_8)));
        } catch (Exception e) {
            throw new SamlProcessingException("Failed to parse SAML XML", e);
        }
    }

    private void trySet(DocumentBuilderFactory dbf, String feature, boolean value) {
        try {
            dbf.setFeature(feature, value);
        } catch (Exception ignored) {
        }
    }

    private XPath newXPath() {
        XPathFactory xpf = XPathFactory.newInstance();
        XPath xpath = xpf.newXPath();
        xpath.setNamespaceContext(new NamespaceContext() {
            @Override
            public String getNamespaceURI(String prefix) {
                if (prefix == null) return XMLConstants.NULL_NS_URI;
                return switch (prefix) {
                    case "samlp" -> NS_SAMLP;
                    case "saml" -> NS_SAML;
                    case "ds" -> NS_DS;
                    default -> XMLConstants.NULL_NS_URI;
                };
            }

            @Override
            public String getPrefix(String namespaceURI) {
                if (NS_SAMLP.equals(namespaceURI)) return "samlp";
                if (NS_SAML.equals(namespaceURI)) return "saml";
                if (NS_DS.equals(namespaceURI)) return "ds";
                return null;
            }

            @Override
            public Iterator<String> getPrefixes(String namespaceURI) {
                String p = getPrefix(namespaceURI);
                return p == null ? Collections.emptyIterator() : Collections.singletonList(p).iterator();
            }
        });
        return xpath;
    }

    private String evalString(XPath xpath, Object item, String expression) {
        try {
            String s = (String) xpath.evaluate(expression, item, XPathConstants.STRING);
            if (s == null) return null;
            s = s.trim();
            return s.isEmpty() ? null : s;
        } catch (XPathExpressionException e) {
            throw new SamlProcessingException("XPath error: " + expression, e);
        }
    }

    private NodeList evalNodeList(XPath xpath, Object item, String expression) {
        try {
            return (NodeList) xpath.evaluate(expression, item, XPathConstants.NODESET);
        } catch (XPathExpressionException e) {
            throw new SamlProcessingException("XPath error: " + expression, e);
        }
    }

    private Instant parseInstantLenient(String s) {
        if (s == null || s.isBlank()) return null;
        try {
            return Instant.parse(s.trim());
        } catch (Exception e) {
            return null;
        }
    }
}

