package com.example.samlsp.web;

import com.example.samlsp.saml.SamlPrincipal;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpSession;
import org.springframework.http.HttpStatus;
import org.springframework.stereotype.Component;
import org.springframework.web.servlet.HandlerInterceptor;

@Component
public class SamlSessionAuthInterceptor implements HandlerInterceptor {

    @Override
    public boolean preHandle(HttpServletRequest request, jakarta.servlet.http.HttpServletResponse response, Object handler) throws Exception {
        String path = request.getRequestURI();
        if (path.startsWith("/saml/acs") || path.startsWith("/saml/logout") || path.startsWith("/actuator")) {
            return true;
        }

        HttpSession session = request.getSession(false);
        if (session == null) {
            response.setStatus(HttpStatus.UNAUTHORIZED.value());
            return false;
        }

        SamlPrincipal principal = (SamlPrincipal) session.getAttribute(SamlAcsController.SESSION_PRINCIPAL_KEY);
        if (principal == null) {
            response.setStatus(HttpStatus.UNAUTHORIZED.value());
            return false;
        }

        return true;
    }
}

package com.example.samlsp.web;

import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.context.annotation.Configuration;
import org.springframework.web.servlet.config.annotation.InterceptorRegistry;
import org.springframework.web.servlet.config.annotation.WebMvcConfigurer;

@Configuration
public class WebConfig implements WebMvcConfigurer {

    private final SamlSessionAuthInterceptor samlSessionAuthInterceptor;

    @Autowired
    public WebConfig(SamlSessionAuthInterceptor samlSessionAuthInterceptor) {
        this.samlSessionAuthInterceptor = samlSessionAuthInterceptor;
    }

    @Override
    public void addInterceptors(InterceptorRegistry registry) {
        registry.addInterceptor(samlSessionAuthInterceptor).addPathPatterns("/**");
    }
}